  "Fasting": {de:"Nüchtern",ru:"Натощак",zh:"空腹",hi:"खाली पेट",nl:"Nuchter",es:"En ayunas",ar:"صائم",fr:"À jeun",pt:"Em jejum",id:"Puasa",bn:"খালি পেটে"},
  "Posture": {de:"Haltung",ru:"Осанка",zh:"姿势",hi:"मुद्रा",nl:"Houding",es:"Postura",ar:"الوضعية",fr:"Posture",pt:"Postura",id:"Postur",bn:"ভঙ্গি"},
